class FreqStack:

    def __init__(self):
        self.freq_map = {}
        self.stacks = {}
        self.max_freq = 0

    def push(self, val: int) -> None:
        self.freq_map[val] = self.freq_map.get(val, 0) + 1
        new_freq = self.freq_map[val]

        self.max_freq = max(self.max_freq, new_freq)

        if new_freq not in self.stacks:
            self.stacks[new_freq] = []
        self.stacks[new_freq].append(val)

    def pop(self) -> int:
        val_to_pop = self.stacks[self.max_freq].pop()

        self.freq_map[val_to_pop] -= 1

        if not self.stacks[self.max_freq]:
            del self.stacks[self.max_freq] # Clean up empty list for this frequency
            self.max_freq -= 1

        return val_to_pop
